import  {useState, useEffect} from 'react';
import { useParams } from 'react-router-dom';
import swal from 'sweetalert';

const Edituser = () =>{
    let{userid} = useParams();
    // it use to capture value from browser url in react
    let[title, pickTitle] = useState("");
    let[content, pickcontent] = useState("");
    
   

    const getuserinfo = () =>{
        let url = "http://localhost:3333/note/"+userid;
        fetch(url)
        .then(response => response.json())
        .then(empinfo =>{
            pickTitle(empinfo.title);
            pickcontent(empinfo.content);
            pickmobile(empinfo.mobile);
           
        })
    }

     useEffect(() =>{
        getuserinfo();
     },[1]);

    const save = () =>{
        let finaldata = new Date().toLocaleString() ;
       let userdata = {
        "name": name,
        "email": email,
        "mobile": mobile,
        "date": finaldata,
        "id" : userid
       };
     
       let url= "http://localhost:3333/user";
       let postoption= {
        headers:{'Content-Type':'application/json'},
        method: "PUT",
        body: JSON.stringify(userdata)
       }
           
       fetch(url,postoption)
       .then(response => response.json())
       .then(userinfo =>{
        swal(name+"", "Updated Successfully !!", "success");
        window.location.href = "#/";
       })
    }

   return(
